			require.NoError(t, err,
				"REGRESSION: Failed to retrieve stored challenge for device %q. "+
					"Challenges must be stored with device IDs to support multiple devices.",
				dev.Id)
			require.NotNil(t, challenge, "stored challenge for device %q is nil", dev.Id)
		}
	})
