WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
See the License for the specific language governing permissions and
limitations under the License.
*/

package main

import (
	"context"
	"encoding/base64"
	"testing"

	"github.com/jonboulle/clockwork"
	"github.com/stretchr/testify/require"

	"github.com/gravitational/teleport"
	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
	"github.com/gravitational/teleport/lib/auth/mocku2f"
	"github.com/gravitational/teleport/lib/auth/u2f"
	"github.com/gravitational/teleport/lib/services"
)

// TestRegression verifies that multiple registered U2F devices all receive
// authentication challenges during login, rather than being limited to a
// single device.
//
// This is a regression test for the issue where users with multiple U2F
// hardware tokens would only see one device presented during login, even
// though they had registered multiple devices.
//
// Bug symptoms:
// 1. Single-device lock-in: After registering multiple U2F tokens, attempting
//    to log in only presents a challenge for one device
// 2. Users cannot select which hardware token to use during authentication
// 3. Device management operations (add, list, delete) don't properly handle
//    multi-device transitions
func TestRegression(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create an auth server for testing
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err, "failed to create test auth server")

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err, "failed to create auth preference")
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err, "failed to set auth preference")

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "u2f-user", []string{"role"})
	require.NoError(t, err, "failed to create user")

	username := user.GetName()
	u2fConfig, err := authPref.GetU2F()
	require.NoError(t, err, "failed to get U2F config")

	// Register the first U2F device
	firstDeviceName := "u2f-key-1"
	firstMockDevice, err := mocku2f.Create()
	require.NoError(t, err, "failed to create first mock U2F device")

	// Initiate registration for the first device
	u2fRegStorage, err := u2f.InMemoryRegistrationStorage(as.AuthServer.Identity)
	require.NoError(t, err, "failed to create U2F registration storage")

	firstChallenge, err := u2f.RegisterInit(ctx, u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fConfig,
		Storage:    u2fRegStorage,
	})
	require.NoError(t, err, "failed to initiate first device registration")

	firstRegResp, err := firstMockDevice.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: firstChallenge.Challenge,
		AppID:     firstChallenge.AppID,
	})
	require.NoError(t, err, "failed to get first device registration response")

	firstDev, err := u2f.RegisterVerify(ctx, u2f.RegisterVerifyParams{
		DevName: firstDeviceName,
		Resp: u2f.RegisterChallengeResponse{
			RegistrationData: firstRegResp.RegistrationData,
			ClientData:       firstRegResp.ClientData,
		},
		StorageKey: username,
		Storage:    u2fRegStorage,
	})
	require.NoError(t, err, "failed to verify first device registration")
	require.NotNil(t, firstDev)

	// Register the second U2F device
	secondDeviceName := "u2f-key-2"
	secondMockDevice, err := mocku2f.Create()
	require.NoError(t, err, "failed to create second mock U2F device")

	// Initiate registration for the second device
	secondChallenge, err := u2f.RegisterInit(ctx, u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fConfig,
		Storage:    u2fRegStorage,
	})
	require.NoError(t, err, "failed to initiate second device registration")

	secondRegResp, err := secondMockDevice.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: secondChallenge.Challenge,
		AppID:     secondChallenge.AppID,
	})
	require.NoError(t, err, "failed to get second device registration response")

	secondDev, err := u2f.RegisterVerify(ctx, u2f.RegisterVerifyParams{
		DevName: secondDeviceName,
		Resp: u2f.RegisterChallengeResponse{
			RegistrationData: secondRegResp.RegistrationData,
			ClientData:       secondRegResp.ClientData,
		},
		StorageKey: username,
		Storage:    u2fRegStorage,
	})
	require.NoError(t, err, "failed to verify second device registration")
	require.NotNil(t, secondDev)

	// Verify both devices are registered in the system
	devices, err := as.AuthServer.GetMFADevices(ctx, username)
	require.NoError(t, err, "failed to get MFA devices")
	require.Len(t, devices, 2, "expected exactly 2 registered U2F devices")

	// Test 1: Verify multi-device authentication challenge generation
	t.Run("multi-device U2F challenge generation for login", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		// Generate authentication challenges for all registered U2F devices
		// This is what the server does when a user tries to log in
		authServer := as.AuthServer
		devs, err := authServer.GetMFADevices(ctx, username)
		require.NoError(t, err, "failed to get MFA devices")

		// Simulate what mfaAuthChallenge does - generate a challenge for each device
		generatedChallenges := make([]string, 0)
		deviceIDs := make([]string, 0)

		for _, dev := range devs {
			if dev.GetU2F() == nil {
				continue
			}
			deviceIDs = append(deviceIDs, dev.Id)

			challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
				AppConfig:  *u2fConfig,
				Dev:        dev,
				Storage:    u2fAuthStorage,
				StorageKey: username,
			})
			require.NoError(t, err, "failed to generate challenge for device %q", dev.Id)
			require.NotNil(t, challenge)

			generatedChallenges = append(generatedChallenges, challenge.Challenge)
		}

		// REGRESSION TEST: The bug manifests as only one challenge being generated
		// when multiple devices are registered. This should generate exactly 2 challenges
		// for the 2 registered U2F devices.
		require.Len(t, generatedChallenges, 2,
			"REGRESSION: Expected authentication challenges for all %d registered U2F devices, "+
				"but only %d challenge(s) were generated. "+
				"When a user has multiple U2F tokens registered, the server must generate a challenge for each device "+
				"so the user can choose which device to authenticate with during login.",
			len(devices), len(generatedChallenges))

		// Verify all challenges are unique
		challengeMap := make(map[string]bool)
		for _, c := range generatedChallenges {
			require.False(t, challengeMap[c], "duplicate challenge generated")
			challengeMap[c] = true
		}
	})

	// Test 2: Verify correct device ID mapping for multi-device challenges
	t.Run("challenge storage with correct device ID mapping", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		authServer := as.AuthServer
		devs, err := authServer.GetMFADevices(ctx, username)
		require.NoError(t, err, "failed to get MFA devices")

		u2fDevices := make(map[string]*types.MFADevice)
		for _, dev := range devs {
			if dev.GetU2F() != nil {
				u2fDevices[dev.Id] = dev
			}
		}

		// Generate challenges for all U2F devices
		for _, dev := range u2fDevices {
			challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
				AppConfig:  *u2fConfig,
				Dev:        dev,
				Storage:    u2fAuthStorage,
				StorageKey: username,
			})
			require.NoError(t, err, "failed to generate challenge for device %q", dev.Id)

			// Verify the challenge can be retrieved using the device ID
			retrievedChallenge, err := u2fAuthStorage.GetU2FSignChallenge(username, dev.Id)
			require.NoError(t, err,
				"REGRESSION: Failed to retrieve stored challenge for device %q. "+
					"Each device must have its own stored challenge for multi-device authentication to work correctly.",
				dev.Id)
			require.NotNil(t, retrievedChallenge)
			require.Equal(t, challenge.Challenge, retrievedChallenge.Challenge,
				"retrieved challenge does not match generated challenge for device %q", dev.Id)
		}

		// Verify we have challenges for all devices
		require.Len(t, u2fDevices, 2,
			"REGRESSION: Expected 2 U2F devices to be registered, but got %d",
			len(u2fDevices))
	})

	// Test 3: Verify client/server compatibility for multi-device challenges
	t.Run("U2F challenge client/server compatibility", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		authServer := as.AuthServer
		devs, err := authServer.GetMFADevices(ctx, username)
		require.NoError(t, err, "failed to get MFA devices")

		// Generate challenges
		authChallenges := make([]*u2f.AuthenticateChallenge, 0)
		for _, dev := range devs {
			if dev.GetU2F() == nil {
				continue
			}
			challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
				AppConfig:  *u2fConfig,
				Dev:        dev,
				Storage:    u2fAuthStorage,
				StorageKey: username,
			})
			require.NoError(t, err)
			authChallenges = append(authChallenges, challenge)
		}

		// Verify each challenge has required fields
		require.Len(t, authChallenges, 2, "expected 2 authentication challenges")

		seenKeyHandles := make(map[string]bool)
		for i, ch := range authChallenges {
			// Each challenge must have a unique key handle pointing to a registered device
			require.NotEmpty(t, ch.KeyHandle, "challenge %d has empty key handle", i)
			require.NotEmpty(t, ch.Challenge, "challenge %d has empty challenge", i)
			require.NotEmpty(t, ch.AppID, "challenge %d has empty AppID", i)

			// Verify key handle is unique (no duplicate challenges)
			require.False(t, seenKeyHandles[ch.KeyHandle],
				"REGRESSION: Duplicate key handle in challenges - device may be presented twice to user")
			seenKeyHandles[ch.KeyHandle] = true
		}

		// Verify key handles are base64-encoded correctly
		for _, ch := range authChallenges {
			_, err := base64.URLEncoding.WithPadding(base64.NoPadding).DecodeString(ch.KeyHandle)
			require.NoError(t, err, "key handle is not valid base64: %s", ch.KeyHandle)
		}
	})

	// Test 4: Verify challenge response validation with multiple devices
	t.Run("multi-device authentication response validation", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		authServer := as.AuthServer
		devs, err := authServer.GetMFADevices(ctx, username)
		require.NoError(t, err, "failed to get MFA devices")

		u2fDevices := make(map[string]*types.MFADevice)
		mockDevices := make(map[string]*mocku2f.Key)

		// Map real devices to their mock versions
		for i, dev := range devs {
			if dev.GetU2F() == nil {
				continue
			}
			u2fDevices[dev.Id] = dev

			// Use the pre-registered mock devices
			if i == 0 {
				mockDevices[dev.Id] = firstMockDevice
			} else if i == 1 {
				mockDevices[dev.Id] = secondMockDevice
			}
		}

		// Generate challenges for each device
		challengesByDevice := make(map[string]*u2f.AuthenticateChallenge)
		for deviceID, dev := range u2fDevices {
			challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
				AppConfig:  *u2fConfig,
				Dev:        dev,
				Storage:    u2fAuthStorage,
				StorageKey: username,
			})
			require.NoError(t, err)
			challengesByDevice[deviceID] = challenge
		}

		// Test that we can verify responses from each device
		for deviceID, dev := range u2fDevices {
			challenge, exists := challengesByDevice[deviceID]
			require.True(t, exists, "challenge not found for device %s", deviceID)

			// Get a mock device to generate a response
			var mockDevice *mocku2f.Key
			if deviceID == firstDev.Id {
				mockDevice = firstMockDevice
			} else {
				mockDevice = secondMockDevice
			}

			// Generate a signature response from the mock device
			mockResp, err := mockDevice.SignResponse(&u2f.AuthenticateChallenge{
				Challenge: challenge.Challenge,
				KeyHandle: challenge.KeyHandle,
				AppID:     challenge.AppID,
			})
			require.NoError(t, err, "failed to sign challenge for device %s", deviceID)

			// Verify the response can be validated against the stored challenge
			err = u2f.AuthenticateVerify(ctx, u2f.AuthenticateVerifyParams{
				Dev: dev,
				Resp: u2f.AuthenticateChallengeResponse{
					KeyHandle:     mockResp.KeyHandle,
					SignatureData: mockResp.SignatureData,
					ClientData:    mockResp.ClientData,
				},
				Storage:    u2fAuthStorage,
				StorageKey: username,
				Clock:      clock,
			})
			require.NoError(t, err,
				"REGRESSION: Failed to verify authentication response from device %q. "+
					"Multi-device authentication requires that each device's response can be validated independently.",
				deviceID)
		}
	})
}

