			err = u2f.AuthenticateVerify(ctx, u2f.AuthenticateVerifyParams{
				Dev: dev,
				Resp: u2f.AuthenticateChallengeResponse{
					KeyHandle:     mockResp.KeyHandle,
					SignatureData: mockResp.SignatureData,
					ClientData:    mockResp.ClientData,
				},
				Storage:    u2fAuthStorage,
				StorageKey: username,
				Clock:      clock,
			})
			require.NoError(t, err,
				"REGRESSION: Failed to verify authentication response from device %q. "+
					"Multi-device authentication requires that each device's response can be validated independently.",
				deviceID)
		}
	})
